#include <stdio.h>

float bilinear_interpolation(float q11, float q12, float q21, float q22, float x, float y) {
 float a = (q11 * (1 - x) + q21 * x) * (1 - y);
 float b = (q12 * (1 - x) + q22 * x) * y;
 return a + b;
}

int main() {
 float q11 = 1.0, q12 = 2.0, q21 = 3.0, q22 = 4.0;
 float x = 0.5, y = 0.5;
 float result = bilinear_interpolation(q11, q12, q21, q22, x, y);
 printf("Result: %f\n", result);
 return 0;
}
